+    /// Auto-initialize all MoE optimizations for maximum performance
+    /// Call this once after loading the GGUF file to enable:
+    /// 1. Static Pinning (top 4 experts based on Zipf profile)
+    /// 2. Shadow Router (2-layer lookahead prefetch)
+    /// 3. Oracle Prefetch (temporal locality prediction)
+    /// 4. Dynamic Top-1 (skip cold experts) - already enabled by default
+    pub fn autoInitOptimizations(
+        self: *Self,
+        gguf_loader: anytype,
+        expert_gate_weights: [8][]const u8,
+        expert_up_weights: [8][]const u8,
+        expert_down_weights: [8][]const u8,
+        n_layers: u32,
+    ) !void {
+        log.info("🚀 Auto-initializing MoE optimizations for 30+ tok/s...", .{});
+
+        // 1. Load expert profile and pin hot experts
+        const expert_profiler = @import("expert_profiler.zig");
+        if (expert_profiler.loadProfile(self.allocator, "mixtral_default")) |profile| {
+            defer self.allocator.free(profile.model_hash);
+
+            log.info("📋 Loaded expert profile: pins [{d}, {d}, {d}, {d}]", .{
+                profile.recommended_pins[0],
+                profile.recommended_pins[1],
+                profile.recommended_pins[2],
+                profile.recommended_pins[3],
+            });
+
+            // Pin the recommended experts
+            var pin_gate: [4][]const u8 = undefined;
+            var pin_up: [4][]const u8 = undefined;
+            var pin_down: [4][]const u8 = undefined;
+
+            for (0..4) |i| {
+                const expert_id = profile.recommended_pins[i];
+                pin_gate[i] = expert_gate_weights[expert_id];
+                pin_up[i] = expert_up_weights[expert_id];
+                pin_down[i] = expert_down_weights[expert_id];
+            }
+
+            try self.pinExperts(&profile.recommended_pins, &pin_gate, &pin_up, &pin_down);
+        } else |_| {
+            log.info("📋 No expert profile found, using default pins [0, 4, 2, 6]", .{});
+
+            // Use default Zipf-based pins
+            const default_pins = [_]u8{ 0, 4, 2, 6 };
+            var pin_gate: [4][]const u8 = undefined;
+            var pin_up: [4][]const u8 = undefined;
+            var pin_down: [4][]const u8 = undefined;
+
+            for (0..4) |i| {
+                pin_gate[i] = expert_gate_weights[default_pins[i]];
+                pin_up[i] = expert_up_weights[default_pins[i]];
+                pin_down[i] = expert_down_weights[default_pins[i]];
+            }
+
+            try self.pinExperts(&default_pins, &pin_gate, &pin_up, &pin_down);
+        }
+
+        // 2. Load all shadow routers for predictive pipelining
+        self.loadAllRouters(gguf_loader, n_layers) catch |err| {
+            log.warn("⚠️  Shadow Router init failed: {s}", .{@errorName(err)});
+        };
+
+        // 3. Turbo mode (Dynamic Top-1) is already enabled by default
+        log.info("⚡ Turbo Mode: ENABLED (skip cold experts)", .{});
+
+        // 4. Oracle Prefetch is automatic in moeFFN_Q8_Batched
+        log.info("🔮 Oracle Prefetch: ENABLED (temporal locality)", .{});
+
+        // Summary
+        log.info("", .{});
+        log.info("✅ MoE optimizations ready!", .{});
+        log.info("   • Static Pinning: {d} experts ({d:.1}GB)", .{
+            self.pinned_expert_count,
+            @as(f32, @floatFromInt(self.pinned_expert_count)) * 0.8,
+        });
+        log.info("   • Shadow Router: {s}", .{
+            if (self.shadow_router_enabled) "ENABLED" else "DISABLED",
+        });
+        log.info("   • Dynamic Top-1: ENABLED", .{});
+        log.info("   • Oracle Prefetch: ENABLED", .{});
+        log.info("", .{});
+    }
+
+    /// Quick initialization without GGUF loader (just pin experts)
+    pub fn autoInitPinning(
+        self: *Self,
+        expert_gate_weights: [8][]const u8,
+        expert_up_weights: [8][]const u8,
+        expert_down_weights: [8][]const u8,
+    ) !void {
+        // Try to load profile, fall back to defaults
+        const expert_profiler = @import("expert_profiler.zig");
+        const pins = if (expert_profiler.loadProfile(self.allocator, "mixtral_default")) |profile| blk: {
+            defer self.allocator.free(profile.model_hash);
+            break :blk profile.recommended_pins;
+        } else |_| [_]u8{ 0, 4, 2, 6 };
+
+        var pin_gate: [4][]const u8 = undefined;
+        var pin_up: [4][]const u8 = undefined;
+        var pin_down: [4][]const u8 = undefined;
+
+        for (0..4) |i| {
+            pin_gate[i] = expert_gate_weights[pins[i]];
+            pin_up[i] = expert_up_weights[pins[i]];
+            pin_down[i] = expert_down_weights[pins[i]];
+        }
+
+        try self.pinExperts(&pins, &pin_gate, &pin_up, &pin_down);
+        log.info("✅ Auto-pinned experts [{d}, {d}, {d}, {d}]", .{ pins[0], pins[1], pins[2], pins[3] });
+    }
+
     pub fn deinit(self: *Self) void {
         // Free pinned expert memory first
         self.unpinExperts();
